// src/app/core/interceptors/jwt.interceptor.ts
var jwtInterceptor = (req, next) => {
  const auth = inject(AuthService);
  const token = auth.getAccessToken();
  if (token) {
    req = req.clone({
      setHeaders: { Authorization: `Bearer ${token}` }
    });
  }
  return next(req);
};

// src/app/core/interceptors/error.interceptor.ts
var errorInterceptor = (req, next) => {
  const auth = inject(AuthService);
  const snackBar = inject(MatSnackBar);
  return next(req).pipe(catchError((error) => {
    if (error.status === 401) {
      auth.logout();
      snackBar.open("Session expired. Please log in again.", "Close", {
        duration: 4e3,
        panelClass: ["error-snack"]
      });
    } else if (error.status === 403) {
      snackBar.open("You do not have permission to do that.", "Close", {
        duration: 4e3,
        panelClass: ["error-snack"]
      });
    } else if (error.status === 500) {
      snackBar.open("A server error occurred. Please try again later.", "Close", {
        duration: 5e3,
        panelClass: ["error-snack"]
      });
    }
    return throwError(() => error);
  }));
};

// src/app/app.config.ts
var appConfig = {
  providers: [
    provideRouter(routes, withComponentInputBinding(), withViewTransitions()),
    provideHttpClient(withInterceptors([jwtInterceptor, errorInterceptor])),
    provideAnimations(),
    provideCharts(withDefaultRegisterables())
  ]
};

// src/main.ts
bootstrapApplication(AppComponent, appConfig).catch(console.error);
